(function(){var body=document.body;var menu=document.getElementById("site-mobile-menu");var search=document.getElementById("site-mobile-search");var contact=document.getElementById("site-contact-modal");if(!menu&&!search&&!contact){return}var isMobileViewport=function(){return window.innerWidth<=1024};var setExpanded=function(selector,isOpen){document.querySelectorAll(selector).forEach(function(trigger){trigger.setAttribute("aria-expanded",isOpen?"true":"false")})};var syncBodyState=function(){var hasOpen=(menu&&menu.classList.contains("is-open"))||(search&&search.classList.contains("is-open"))||(contact&&contact.classList.contains("is-open"))||body.classList.contains("site-cart-open");body.classList.toggle("site-mobile-panel-open",!!hasOpen)};var openPanel=function(panel,selector){if(!panel){return}panel.classList.add("is-open");panel.setAttribute("aria-hidden","false");if(selector){setExpanded(selector,true)}syncBodyState()};var closePanel=function(panel,selector){if(!panel){return}panel.classList.remove("is-open");panel.setAttribute("aria-hidden","true");if(selector){setExpanded(selector,false)}syncBodyState()};document.addEventListener("click",function(event){if(event.target.closest("[data-open-mobile-menu]")){event.preventDefault();openPanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]");closePanel(contact,"[data-open-contact-modal]")}if(event.target.closest("[data-close-mobile-menu]")){event.preventDefault();closePanel(menu,"[data-open-mobile-menu]")}if(event.target.closest("[data-open-mobile-search]")){event.preventDefault();openPanel(search,"[data-open-mobile-search]");closePanel(menu,"[data-open-mobile-menu]");closePanel(contact,"[data-open-contact-modal]");var input=search?search.querySelector('input[type="search"]'):null;if(input){window.setTimeout(function(){input.focus()},150)}}if(event.target.closest("[data-close-mobile-search]")){event.preventDefault();closePanel(search,"[data-open-mobile-search]")}if(event.target.closest("[data-open-contact-modal]")){if(!isMobileViewport()){return}event.preventDefault();openPanel(contact,"[data-open-contact-modal]");closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]")}if(event.target.closest("[data-close-contact-modal]")){event.preventDefault();closePanel(contact,"[data-open-contact-modal]")}});document.addEventListener("keydown",function(event){if(event.key==="Escape"){closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]");closePanel(contact,"[data-open-contact-modal]")}});document.addEventListener("DOMContentLoaded",syncBodyState);window.addEventListener("resize",function(){if(window.innerWidth>1024){closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]")}closePanel(contact,"[data-open-contact-modal]")})})();
